using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10.00m * i,
                Quantity = i,
            })
            .ToList();

    // --- CreateOrder: success cases ---

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateSampleItems();

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithNonEmptyId()
    {
        var items = CreateSampleItems();

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithSameItems()
    {
        var items = CreateSampleItems(2);

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", CreateSampleItems());

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}.");
    }

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithGivenItems_CalculatesCorrectTotal(
        decimal price, int quantity, decimal expectedTotal)
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = price, Quantity = quantity },
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(decimal price, int quantity, decimal expectedTotal)> TotalCalculationData =>
    [
        (10.00m, 1, 10.00m),
        (5.50m, 3, 16.50m),
        (0.00m, 5, 0.00m),
        (100.00m, 0, 0.00m),
    ];

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsAllItemTotals()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10.00m, Quantity = 2 },  // 20
            new() { ProductName = "B", Price = 5.00m, Quantity = 3 },   // 15
            new() { ProductName = "C", Price = 1.50m, Quantity = 4 },   // 6
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(41.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var order1 = _service.CreateOrder("cust-1", CreateSampleItems());
        var order2 = _service.CreateOrder("cust-1", CreateSampleItems());

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- CreateOrder: validation / error cases ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateSampleItems()));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateSampleItems());

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateSampleItems());
        _service.CreateOrder("cust-1", CreateSampleItems());
        _service.CreateOrder("cust-2", CreateSampleItems());

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        _service.CreateOrder("cust-1", CreateSampleItems());

        var result = _service.GetOrdersByCustomer("cust-999");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersAtAll_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.IsEmpty(result);
    }
}

